# Dotenv loader for bash-cli
# Inspired by Symfony\Component\Dotenv
# Loads environment variables from .env files

# Regex pattern for valid variable names (matching Symfony's VARNAME_REGEX)
readonly ENV_VARNAME_REGEX='^[a-zA-Z_][a-zA-Z0-9_]*$'

# Track which variables were loaded by dotenv
declare -g DOTENV_VARS=""

# Parse a single line from .env file
# Arguments:
#   $1 - line: The line to parse
#   $2 - override: Whether to override existing variables (default: false)
parse_env_line() {
    local line="$1"
    local override="${2:-false}"
    local name value

    # Skip empty lines
    [[ -z "$line" ]] && return 0

    # Skip comments
    [[ "$line" =~ ^[[:space:]]*# ]] && return 0

    # Remove 'export ' prefix if present
    line="${line#export }"
    line="${line#export	}"  # Also handle tab

    # Check if line contains '='
    if [[ ! "$line" =~ = ]]; then
        return 0
    fi

    # Split on first '='
    name="${line%%=*}"
    value="${line#*=}"

    # Trim whitespace from name
    name="${name#"${name%%[![:space:]]*}"}"
    name="${name%"${name##*[![:space:]]}"}"

    # Validate variable name
    if [[ ! "$name" =~ $ENV_VARNAME_REGEX ]]; then
        return 0
    fi

    # Process the value
    value=$(parse_env_value "$value")

    # Check if variable already exists and was NOT loaded by dotenv
    # Variables loaded by dotenv can be overridden by subsequent .env files
    if [[ -n "${!name+x}" ]] && [[ "$override" != "true" ]]; then
        # Check if this variable was loaded by dotenv
        local is_dotenv_var=false
        if [[ -n "$DOTENV_VARS" ]]; then
            IFS=',' read -ra loaded_vars <<< "$DOTENV_VARS"
            for loaded_var in "${loaded_vars[@]}"; do
                if [[ "$loaded_var" == "$name" ]]; then
                    is_dotenv_var=true
                    break
                fi
            done
        fi

        # If not a dotenv var, skip (don't override system variables)
        if [[ "$is_dotenv_var" != "true" ]]; then
            return 0
        fi
    fi

    # Export the variable
    export "$name=$value"

    # Track loaded variable (add if not already tracked)
    if [[ "$DOTENV_VARS" == "" ]]; then
        DOTENV_VARS="$name"
    elif [[ ",$DOTENV_VARS," != *",$name,"* ]]; then
        DOTENV_VARS="$DOTENV_VARS,$name"
    fi
}

# Parse environment variable value
# Handles quoted strings, variable expansion, and special characters
# Arguments:
#   $1 - value: The value to parse
parse_env_value() {
    local value="$1"
    local result=""

    # Trim leading/trailing whitespace
    value="${value#"${value%%[![:space:]]*}"}"
    value="${value%"${value##*[![:space:]]}"}"

    # Handle single-quoted strings (no variable expansion)
    if [[ "$value" =~ ^\'.*\'$ ]]; then
        # Remove surrounding single quotes
        value="${value#\'}"
        value="${value%\'}"
        echo "$value"
        return 0
    fi

    # Handle double-quoted strings (with variable expansion)
    if [[ "$value" =~ ^\".*\"$ ]]; then
        # Remove surrounding double quotes
        value="${value#\"}"
        value="${value%\"}"

        # Expand variables within double quotes
        value=$(expand_env_variables "$value")

        # Handle escape sequences
        value="${value//\\n/$'\n'}"
        value="${value//\\r/$'\r'}"
        value="${value//\\t/$'\t'}"
        value="${value//\\\"/\"}"
        value="${value//\\\\/\\}"

        echo "$value"
        return 0
    fi

    # Handle unquoted values
    # Remove inline comments (not within quotes)
    if [[ "$value" =~ ^([^#]*[^[:space:]])([[:space:]]+#.*)$ ]]; then
        value="${BASH_REMATCH[1]}"
    fi

    # Expand variables in unquoted values
    value=$(expand_env_variables "$value")

    echo "$value"
}

# Expand environment variables in a string
# Supports: $VAR, ${VAR}, ${VAR:-default}, ${VAR:=default}
# Arguments:
#   $1 - text: The text containing variables to expand
expand_env_variables() {
    local text="$1"
    local result=""
    local pos=0
    local len="${#text}"

    while [[ $pos -lt $len ]]; do
        # Find next variable reference
        local remaining="${text:$pos}"

        # Match ${VAR:-default}, ${VAR:=default}, ${VAR}, or $VAR
        if [[ "$remaining" =~ ^\$\{([a-zA-Z_][a-zA-Z0-9_]*)(:-([^}]*))?\} ]]; then
            # Matched ${VAR} or ${VAR:-default}
            local var_name="${BASH_REMATCH[1]}"
            local has_default="${BASH_REMATCH[2]}"
            local default_value="${BASH_REMATCH[3]}"
            local match_len="${#BASH_REMATCH[0]}"

            # Get variable value using indirect expansion (safe for unset vars)
            local var_value=""
            if [[ -v "$var_name" ]]; then
                var_value="${!var_name}"
            fi

            # Apply default if variable is unset or empty
            if [[ -z "$var_value" && -n "$has_default" ]]; then
                var_value="$default_value"
            fi

            result+="$var_value"
            pos=$((pos + match_len))

        elif [[ "$remaining" =~ ^\$\{([a-zA-Z_][a-zA-Z0-9_]*):=([^}]*)\} ]]; then
            # Matched ${VAR:=default} - set variable if unset
            local var_name="${BASH_REMATCH[1]}"
            local default_value="${BASH_REMATCH[2]}"
            local match_len="${#BASH_REMATCH[0]}"

            # Get or set variable value (safe for unset vars)
            local var_value=""
            if [[ -v "$var_name" ]]; then
                var_value="${!var_name}"
            fi
            if [[ -z "$var_value" ]]; then
                export "$var_name=$default_value"
                var_value="$default_value"
            fi

            result+="$var_value"
            pos=$((pos + match_len))

        elif [[ "$remaining" =~ ^\$([a-zA-Z_][a-zA-Z0-9_]*) ]]; then
            # Matched $VAR (without braces)
            local var_name="${BASH_REMATCH[1]}"
            local match_len="${#BASH_REMATCH[0]}"

            # Get variable value using indirect expansion (safe for unset vars)
            local var_value=""
            if [[ -v "$var_name" ]]; then
                var_value="${!var_name}"
            fi
            result+="$var_value"
            pos=$((pos + match_len))

        else
            # No variable found, copy one character
            result+="${text:$pos:1}"
            pos=$((pos + 1))
        fi
    done

    echo "$result"
}

# Load environment variables from a .env file
# Arguments:
#   $1 - file_path: Path to the .env file
#   $2 - override: Whether to override existing variables (default: false)
load_env_from_file() {
    local file_path="$1"
    local override="${2:-false}"
    local line

    # Check if file exists and is readable
    if [[ ! -f "$file_path" ]] || [[ ! -r "$file_path" ]]; then
        return 0
    fi

    # Check for BOM (Byte Order Mark) - not supported
    if [[ -f "$file_path" ]]; then
        local first_bytes
        first_bytes=$(head -c 3 "$file_path" | od -An -tx1 | tr -d ' \n')
        if [[ "$first_bytes" == "efbbbf" ]]; then
            error "Loading files starting with a byte-order-mark (BOM) is not supported: $file_path"
            return 1
        fi
    fi

    # Read file line by line
    while IFS= read -r line || [[ -n "$line" ]]; do
        parse_env_line "$line" "$override"
    done < "$file_path"

    return 0
}

# Load .env files with environment-specific variants
# Loads in order: .env, .env.local, .env.$env, .env.$env.local
# Arguments:
#   $1 - base_path: Base path for .env files (default: project root)
#   $2 - env: Environment name (e.g., dev, prod, test) - optional
#   $3 - override: Whether to override existing variables (default: false)
load_env() {
    local base_path="${1:-.}"
    local env="${2:-}"
    local override="${3:-false}"
    local env_file

    # Ensure base_path is absolute
    if [[ ! "$base_path" =~ ^/ ]]; then
        base_path="$(cd "$base_path" 2>/dev/null && pwd)" || base_path="."
    fi

    # Load main .env file (or .env.dist as fallback)
    env_file="$base_path/.env"
    if [[ -f "$env_file" ]]; then
        load_env_from_file "$env_file" "$override"
    elif [[ -f "$base_path/.env.dist" ]]; then
        load_env_from_file "$base_path/.env.dist" "$override"
    fi

    # Determine environment if not specified
    if [[ -z "$env" ]]; then
        env="${APP_ENV:-${CLI_ENV:-dev}}"
    fi

    # Load .env.local (skip in test environment - tests should be consistent)
    if [[ "$env" != "test" ]] && [[ -f "$base_path/.env.local" ]]; then
        load_env_from_file "$base_path/.env.local" "$override"
        # Update env in case it was overridden
        env="${APP_ENV:-${CLI_ENV:-$env}}"
    fi

    # Skip environment-specific files if env is 'local'
    if [[ "$env" == "local" ]]; then
        return 0
    fi

    # Load environment-specific .env file
    if [[ -n "$env" ]] && [[ -f "$base_path/.env.$env" ]]; then
        load_env_from_file "$base_path/.env.$env" "$override"
    fi

    # Load environment-specific local .env file
    if [[ -n "$env" ]] && [[ -f "$base_path/.env.$env.local" ]]; then
        load_env_from_file "$base_path/.env.$env.local" "$override"
    fi

    # Export DOTENV_VARS for tracking
    export DOTENV_VARS

    return 0
}

# Load .env files with override enabled
# Arguments:
#   $1 - base_path: Base path for .env files (default: project root)
#   $2 - env: Environment name (optional)
overload_env() {
    load_env "$1" "$2" "true"
}

# Get the project root directory (where .env files should be located)
get_env_project_root() {
    # Try to use get_project_root if available (from loader.sh)
    if declare -f get_project_root > /dev/null 2>&1; then
        get_project_root
    elif declare -f get_script_dir > /dev/null 2>&1; then
        local script_dir
        script_dir=$(get_script_dir)
        # If we're in dist/, go up one level
        if [[ "$(basename "$script_dir")" == "dist" ]]; then
            dirname "$script_dir"
        else
            echo "$script_dir"
        fi
    else
        # Fallback: use current directory
        pwd
    fi
}

