# Helper to generate alias (e.g., docker:images -> d:i)
generate_alias() {
    local cmd="$1"
    local alias=""
    IFS=':' read -ra parts <<< "$cmd"
    for part in "${parts[@]}"; do
        alias+="${part:0:1}:"
    done
    alias="${alias%:}"
    echo "$alias"
}

# Get the directory of this script (even if symlinked)
get_script_dir() {
    local SOURCE="${BASH_SOURCE[0]}"
    while [ -h "$SOURCE" ]; do
        DIR="$(cd -P "$(dirname "$SOURCE")" >/dev/null 2>&1 && pwd)"
        SOURCE="$(readlink "$SOURCE")"
        [[ $SOURCE != /* ]] && SOURCE="$DIR/$SOURCE"
    done
    DIR="$(cd -P "$(dirname "$SOURCE")" >/dev/null 2>&1 && pwd)"
    echo "$DIR"
}

