# Colored output functions
error()   { echo -e "${RED}[ERROR]${NC} $1" >&2; }
success() { echo -e "${GREEN}[SUCCESS]${NC} $1"; }
warning() { echo -e "${YELLOW}[WARNING]${NC} $1"; }
info()    { echo -e "${BLUE}[INFO]${NC} $1"; }
debug()   { echo -e "${PURPLE}[DEBUG]${NC} $1"; }
test_info() { echo -e "${BLUE}[TEST] $1"; }
test_pass() { echo -e "${GREEN}✓${NC} $1"; ((++TESTS_PASSED)); ((++TESTS_TOTAL)); }
test_fail() { echo -e "${RED}[FAIL]${NC} $1" >&2; ((++TESTS_FAILED)); ((++TESTS_TOTAL)); }
test_warn() { echo -e "${YELLOW}[WARN]${NC} $1"; }
check() { echo -e "${GREEN}✓${NC} $1"; }

