# ============================================================================
# Module: 02.utils/progress.sh
# ============================================================================

# Progress bar
show_progress() {
    local current=$1
    local total=$2
    local width=40
    local percentage=$((current * 100 / total))
    local completed=$((current * width / total))
    local remaining=$((width - completed))

    printf "\r${BLUE}Progress: [${GREEN}"
    printf "%0.s█" $(seq 1 $completed)
    printf "${NC}"
    printf "%0.s▒" $(seq 1 $remaining)
    printf "${BLUE}] %d%% (%d/%d)${NC}" $percentage $current $total

    if [ $current -eq $total ]; then
        echo
    fi
}

# ============================================================================
# Module: 02.utils/table.sh
# ============================================================================

# Table rendering
print_table() {
    local -n headers=$1
    local -n rows=$2
    local -a widths

    for i in "${!headers[@]}"; do
        widths[$i]=${#headers[$i]}
        for row in "${rows[@]}"; do
            IFS='|' read -ra cols <<< "$row"
            if [[ ${#cols[$i]} -gt ${widths[$i]} ]]; then
                widths[$i]=${#cols[$i]}
            fi
        done
    done

    printf "${BOLD}"
    for i in "${!headers[@]}"; do
        printf "%-*s  " "${widths[$i]}" "${headers[$i]}"
    done
    printf "${NC}\n"

    for i in "${!headers[@]}"; do
        printf "%-*s  " "${widths[$i]}" "$(printf -- '-%.0s' $(seq 1 ${widths[$i]}))"
    done
    echo

    for row in "${rows[@]}"; do
        IFS='|' read -ra cols <<< "$row"
        for i in "${!cols[@]}"; do
            printf "%-*s  " "${widths[$i]}" "${cols[$i]}"
        done
        echo
    done
}

