# Argument parser
parse_arguments() {
    local -n parsed_args=$1
    shift

    parsed_args["_positional"]=""

    while [[ $# -gt 0 ]]; do
        case $1 in
            --*=*)
                key="${1#--}"
                key="${key%%=*}"
                value="${1#*=}"
                parsed_args["$key"]="$value"
                ;;
            --*)
                key="${1#--}"
                if [[ $# -gt 1 && ! $2 =~ ^- ]]; then
                    parsed_args["$key"]="$2"
                    shift
                else
                    parsed_args["$key"]="true"
                fi
                ;;
            -*)
                key="${1#-}"
                if [[ $# -gt 1 && ! $2 =~ ^- ]]; then
                    parsed_args["$key"]="$2"
                    shift
                else
                    parsed_args["$key"]="true"
                fi
                ;;
            *)
                parsed_args["_positional"]="${parsed_args["_positional"]} $1"
                ;;
        esac
        shift
    done
}

